INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-f0899a01-moex-00007', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '下列關於正當防衛與緊急避難的敘述，何者錯誤？', '["正當防衛只能針對實施不法侵害之人或動物；緊急避難則可以針對無辜第三人", "正當防衛之防衛情狀僅限於人的不法侵害；緊急避難之緊急危難則不限於人的侵害、也有可能 是自然狀態之危難", "正當防衛行為原則上毋須考慮利益衡量（權衡）；緊急避難行為則必須要檢驗利益衡量（權衡）", "公務上負有特別義務者不得為自己而主張緊急避難，正當防衛則無此限制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00008', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '甲教唆乙殺A，乙因而心生殺A之意。某日，乙基於殺意持刀砍殺A多刀，A倒地流血不止，此 時乙見 A 血流不止之慘狀，忽然心生悔悟決定緊急將 A 送醫急救，A 經緊急手術後在醫院加護 病房接受照護，不料當晚發生大地震，A遭因地震掉落之物砸死。試問甲、乙之行為應如何論罪？', '["乙成立普通殺人既遂罪，甲成立教唆殺人既遂罪", "乙成立普通殺人未遂罪，甲成立教唆殺人未遂罪", "乙成立殺人未遂罪之中止犯，甲成立教唆殺人未遂罪之中止犯", "乙成立殺人未遂罪之中止犯，甲成立教唆殺人未遂罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00009', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '甲出重金要求13歲之乙在法庭上作偽證，乙受重金誘惑而答應，之後乙接受傳喚出庭作證時，雖 然依法無庸具結，但仍然在法庭上為虛偽陳述。試問本題中甲、乙可能應負之刑責？', '["甲成立教唆偽證罪，乙成立偽證罪", "甲成立教唆偽證罪，乙無罪", "甲成立偽證罪之間接正犯，乙無罪", "甲、乙均無罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00010', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '大學生A參加學校演講活動，領取一個餐盒，因上課時間已到來不及吃，乃將便當先寄放在同學 甲的住處，請甲先幫他冰起來以避免食物變質，欲等上完課後作為餐點食用。午後，甲因嘴饞， 竟擅自吃掉該餐盒內的麵包及飲料。試問甲之行為應成立何罪？', '["竊盜罪", "詐欺罪", "侵占罪", "背信罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00011', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '依刑法效力之規定，我國公民於下列何種情形適用我國刑法？', '["在泰國與友人共同施用毒品", "在菲律賓竊取美國觀光客的財物", "在柬埔寨參加犯罪組織並騙取日本人金錢", "具公務員身分者在越南湮滅關係國人為刑事被告案件之證據"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00012', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '甲長期施用安非他命，未曾至精神科就診，也無病識感，因不滿同住員工宿舍的A之日常行為， 又懷疑A要對自己不利，因此心存積怨。某日，甲施用毒品後聽到A在宿舍餐廳喝酒喧嘩，一時 氣憤，基於殺人犯意拿著牛排刀刺入A的背部，A經送醫急救，因受有左上背部銳器刺傷，致左 側胸腔大量血胸、左肺塌陷，不治死亡。依鑑定報告書判斷，甲於案發當時的精神狀態，係因吸 食安非他命導致殺人行為，其辨識行為違法或依其辨識而行為之能力顯著減低。甲的刑責為何？', '["過失致死罪", "傷害致死罪", "殺人既遂罪，適用刑法第19條第3項而不得減輕其刑", "殺人既遂罪，依刑法第19條第2項規定，得減輕其刑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00013', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '甲、乙分別攜帶空氣槍與開山刀侵入A位於1樓的商店，要脅A關閉鐵門並交出財物，兩人搜刮 財物且將店內的監視器主機拔除後，迅速逃離現場。甲、乙成立何罪？', '["強盜罪", "恐嚇取財罪", "加重強盜罪", "湮滅刑事證據罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00014', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '有關妨害性自主罪之敘述，下列何者正確？', '["強制猥褻罪處罰未遂行為", "對配偶犯強制性交罪，得減輕或免除其刑", "未滿18歲之人犯刑法第227條之罪者，須告訴乃論", "利用權勢為性交，因而致被害人羞忿自殺者，成立加重結果犯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00015', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '刑法第339條之4為加重詐欺罪，下列何者屬詐欺罪之加重情形？', '["2人以上共同犯之", "冒用外國政府機關名義犯之", "對未滿14歲之男女犯之", "以科技方法製作關於他人不實影像之方法犯之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00016', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '刑事訴訟運作過程中，辯護人扮演重要角色。請問下列相關規範何者正確？', '["辯護人於審判中不僅可以檢閱卷宗及證物，並可以對卷證進行抄錄、重製和攝影", "為確保偵查不公開，辯護人於偵查中之羈押審查程序，原則上不得檢閱卷宗及證據", "限制辯護人與羈押之被告接見或互通書信，應用限制書。限制書應由檢察官簽名，不得由檢察 事務官為之", "每一被告選任辯護人的人數，視案件性質與被告需要而定，法律並無限制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
